    auto update2 = sqlgen::update<Order>("status"_c.set("delivered"))
        | sqlgen::where("status"_c == "shipped");

    // Execute both updates and return total affected rows
    auto result1 = update1(conn);
    auto result2 = update2(conn);

    // Assuming both updates succeed, return the sum of affected rows
