namespace generate_sql_dry_run {

struct A {
  sqlgen::PrimaryKey<int> id;
  std::string name;
};

struct B {
  sqlgen::PrimaryKey<int> id;
  int a_id;
  double score;
};

/**
 * This function demonstrates how to build a conditional SQL query.
 * It joins tables A and B, filtering for records where score > 10 and name contains 'x'.
 * Returns: std::string.
 */
std::string generate_sql_dry_run() {
    using namespace sqlgen::literals;

    // Start building query from table A with alias "t1"
    auto query = sqlgen::select_from<A, "t1">("name"_t1, "score"_t2)
        // Add inner join with table B (alias "t2") and join condition
        | sqlgen::inner_join<B, "t2">("id"_t1 == "a_id"_t2)
        // Add where clause with two conditions combined with &&
        | sqlgen::where("score"_t2 > 10 && "name"_t1.like("%x%"))
        // Add order_by clause with score column in descending order
        | sqlgen::order_by("score"_t2.desc())
        // Add limit clause
        | sqlgen::limit(5);

    // Generate SQL string using sqlgen::sqlite::to_sql
    return sqlgen::sqlite::to_sql(query);
}

}  // namespace generate_sql_dry_run
```

