bool update_set_operations() {
  using namespace sqlgen::literals;

  try {
    // 1. Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
      return false;
    }
    auto conn = *conn_result;

    // 2. Create the Account table using write with empty container
    std::vector<Account> empty_accounts;
    auto write_result = sqlgen::write(conn, empty_accounts);
    if (!write_result) {
      return false;
    }

    // 3. Update balances and statuses using set operations
    // Update account with account_id = 1
    auto update_stmt = sqlgen::update<Account>(
        "balance"_c.set(500.0),  // Set balance to 500.0
        "status"_c.set("active") // Set status to "active"
    );

    update_stmt = update_stmt | sqlgen::where("account_id"_c == 1);

    auto update_result = update_stmt(conn);
    if (!update_result) {
      return false;
    }

    // 4. Verify changes persisted by reading the updated data
    auto read_result = sqlgen::read<std::vector<Account>>(conn) | sqlgen::where("account_id"_c == 1);
    auto accounts = read_result(conn);

    if (!accounts) {
      return false;
    }

    // Check if we got exactly one account and verify the updates
    if (accounts->size() != 1) {
      return false;
    }

