```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // 1. Connect to an in-memory database
  auto conn = sqlgen::sqlite::connect(":memory:");

  // 2. Create Department and Employee tables with if_exists and cascade modifiers
  auto drop_dept = sqlgen::drop<Department> | sqlgen::if_exists | sqlgen::cascade;
  auto drop_emp = sqlgen::drop<Employee> | sqlgen::if_exists | sqlgen::cascade;

  // Execute drop operations
  drop_dept(conn);
  drop_emp(conn);

  auto create_dept = sqlgen::create_table<Department>;
  auto create_emp = sqlgen::create_table<Employee>;

  // Execute create operations
  create_dept(conn);
  create_emp(conn);

  // 3. Insert the provided department and employee data
  auto insert_dept = sqlgen::insert(depts);
  auto insert_emp = sqlgen::insert(emps);

  // Execute insert operations
  insert_dept(conn);
  insert_emp(conn);

  // 4. Perform INNER JOIN
  auto inner_query = sqlgen::select_from<Department, "d">(
      "department_name"_d,
      "first_name"_e,
      "last_name"_e,
      "salary"_e
  ) | sqlgen::inner_join<Employee, "e">("department_id"_d == "department_id"_e);

  auto inner_result = inner_query(conn);
  auto inner_range = inner_result.value();
  std::vector<JoinResult> inner_joins;
  for (const auto& row : inner_range) {
    JoinResult result;
    result.department_name = row.department_name;
    result.first_name = row.first_name;
    result.last_name = row.last_name;
    result.salary = row.salary;
    inner_joins.push_back(result);
  }

  // 5. Perform LEFT JOIN
  auto left_query = sqlgen::select_from<Employee, "e">(
      "department_name"_d,
      "first_name"_e,
      "last_name"_e,
      "salary"_e
  ) | sqlgen::left_join<Department, "d">("department_id"_e == "department_id"_d);

  auto left_result = left_query(conn);
  auto left_range = left_result.value();
  std::vector<JoinResult> left_joins;
  for (const auto& row : left_range) {
    JoinResult result;
    result.department_name = row.department_name;
    result.first_name = row.first_name;
    result.last_name = row.last_name;
    result.salary = row.salary;
    left_joins.push_back(result);
  }

  // 6. Perform RIGHT JOIN
  auto right_query = sqlgen::select_from<Department, "d">(
      "department_name"_d,
      "first_name"_e,
      "last_name"_e,
      "salary"_e
  ) | sqlgen::right_join<Employee, "e">("department_id"_d == "department_id"_e);

  auto right_result = right_query(conn);
  auto right_range = right_result.value();
  std::vector<JoinResult> right_joins;
  for (const auto& row : right_range) {
    JoinResult result;
    result.department_name = row.department_name;
    result.first_name = row.first_name;
    result.last_name = row.last_name;
    result.salary = row.salary;
    right_joins.push_back(result);
  }

  // 7. Perform FULL JOIN
  auto full_query = sqlgen::select_from<Department, "d">(
      "department_name"_d,
      "first_name"_e,
      "last_name"_e,
      "salary"_e
  ) | sqlgen::full_join<Employee, "e">("department_id"_d == "department_id"_e);

  auto full_result = full_query(conn);
  auto full_range = full_result.value();
  std::vector<JoinResult> full_joins;
  for (const auto& row : full_range) {
    JoinResult result;
    result.department_name = row.department_name;
    result.first_name = row.first_name;
    result.last_name = row.last_name;
    result.salary = row.salary;
    full_joins.push_back(result);
  }

  // 8. Return comprehensive analysis
  JoinAnalysis analysis;
  analysis.inner_join_results = std::move(inner_joins);
  analysis.left_join_results = std::move(left_joins);
  analysis.right_join_results = std::move(right_joins);
  analysis.full_join_results = std::move(full_joins);

  return analysis;
}

}  // namespace analyze_department_employees
